#include <bits/stdc++.h>
using namespace std;

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int t;
    cin>>t;
    while(t--){
        int a,b;
        cin>>a>>b;
        int gcdValue = gcd(a, b);
        long long lcmValue = (long long)a * b / gcdValue;

        cout << gcdValue << " " << lcmValue << endl;
    }

}

